private InputStream getCurrentStream() throws IOException {
    if (deferredBlockStreams.isEmpty()) {
        throw new IllegalStateException("No current 7z entry (call getNextEntry() first).");
    }

    int i = 0;
    boolean endOfBlocksFound = false;
    while (i < deferredBlockStreams.size()) {
        final InputStream stream = deferredBlockStreams.get(i);

        if (!endOfBlocksFound && stream instanceof BlockInputStream) {
            final long skipBytes = ((BlockInputStream) stream).getSkipBytesCount();

            if (skipBytes == -1L) {
                // Skip until EOF
                IOUtils.skipFully(stream);
            } else if (skipBytes > 0L) {
                // If skip count isn't zero or EOF, then this isn't just an
                // artificial block input stream but rather contains real data.
                endOfBlocksFound = true;
            }
        }

        if (endOfBlocksFound || i + 1 >= deferredBlockStreams.size()) {
            final InputStream resultStream = deferredBlockStreams.remove(i);

            if (!endOfBlocksFound && stream != null && resultStream != stream) {
                stream.close();
            }

            return resultStream;
        }

        i++;
    }

    assert(false);
    return null;
}

